#include <cxxabi.h>
#include <stdio.h>
#include <stdlib.h>

#include <list>

template <typename T> void test() {
  auto mangled = typeid(T).name();
  printf("mangled='%s'\n", mangled);
  int status = 0;
  using abi::__cxa_demangle;
  auto demangled = __cxa_demangle(mangled, 0, 0, &status);
  printf("demangled='%s', status=%d\n", demangled, status);
  free(demangled);
}

int main() {
  test<int>();
  test<char[4]>();
  test<std::list<int>>();
  test<char[4]>();
  test<int>();
}


